custom_fields.value:
[[[
  const watts = Number(entity.state);
  const wat = Number.isFinite(watts) ? `${Math.round(watts)} W` : '--';

  const lastChanged = new Date(entity.last_changed);
  const elapsedMs = Date.now() - lastChanged.getTime();

  let elapsedText = '--';
  if (Number.isFinite(elapsedMs) && elapsedMs >= 0) {
    const minutes = Math.floor(elapsedMs / 60000);
    const hours = Math.floor(minutes / 60);
    const days = Math.floor(hours / 24);

    if (days > 0) {
      elapsedText = `${days}d`;
    } else if (hours > 0) {
      elapsedText = `${hours}h`;
    } else {
      elapsedText = `${Math.max(minutes, 1)}m`;
    }
  }
  if (Number.isFinite(watts) && watts > 0) {
    return `${Math.round(watts)} W`;
  }
  return `${wat} since ${elapsedText}`;
]]]

card.background:
[[[
  const down = Number(states['sensor.speedtest_download']?.state);
  const ping = Number(states['sensor.speedtest_ping']?.state);
  if (!Number.isFinite(down) || !Number.isFinite(ping)) return 'linear-gradient(135deg, #546e7a, #78909c)';
  if (down < 10 || ping > 100) return 'linear-gradient(135deg, #8d6e63, #bcaaa4)';
  if (down < 25 || ping > 50) return 'linear-gradient(135deg, #c49a3a, #e6c76a)';
  return 'linear-gradient(135deg, #2f7a6d, #68b0a1)';
]]]

